(function(){
  // 开关函数
  window.toggleIphone = function(){
    const container = document.getElementById("iphone17-container");
    if (!container) return;
    container.style.display = (container.style.display === "none") ? "block" : "none";
  }

  // 可选：绑定快捷键 H
  document.addEventListener("keydown", (e) => {
    if (e.key === "h" || e.key === "H") {
      window.toggleIphone();
    }
  });
})();


(function(){

function initIphone(){

if(window.innerWidth < 900) return
if(document.querySelector("#iphone17-container")) return


/* CSS */

if(!document.querySelector("#iphone-style")){

const style=document.createElement("style")
style.id="iphone-style"

style.innerHTML=`

#iphone17-container{
position:fixed;
top:160px;
left:80px;
width:280px;
z-index:10;
cursor:move;
}

/* 手机 */

.iphone17{
width:320px;
height:660px;
border-radius:70px;
padding:12px;
background:#111;

box-shadow:
0 40px 100px rgba(0,0,0,.8);
}

/* 屏幕 */

.iphone-screen{
width:100%;
height:100%;
border-radius:48px;
overflow:hidden;
background:#000;
cursor:grab;
position:relative;
}

/* Dynamic Island */

/* 外层负责居中 */

.dynamic-island{

position:absolute;
top:12px;

left:35%;
transform:translateX(-50%);

width:100px;
height:28px;

background:#000;
border-radius:20px;

z-index:20;

animation:islandBreath 10s ease-in-out infinite;

}

/* 内层负责显示 */

.island-core{
width:100%;
height:100%;
background:#000;
border-radius:20px;

animation:islandBreath 10s ease-in-out infinite;
}

/* 图片轨道 */

.photo-track{
display:flex;
height:100%;
will-change:transform;
}

/* 图片 */

.photo-track img{
width:100%;
height:100%;
object-fit:cover;
flex-shrink:0;
pointer-events:none;
user-select:none;
}

@keyframes islandBreath{

0%{
transform:scale(1);
}

50%{
transform:scale(1.06);
}

100%{
transform:scale(1);
}

}

.photo-track img{
pointer-events:none;
}



@media(max-width:900px){
#iphone17-container{display:none;}
}

`

document.head.appendChild(style)

}


/* HTML */

const container=document.createElement("div")

container.id="iphone17-container"

container.innerHTML=`

<div class="iphone17">
    <div class="iphone-screen" id="iphoneScreen">
        <div class="dynamic-island">
            <div class="island-core"></div>
</div>



<div class="photo-track" id="iphoneTrack">

<img src="data:image/jpeg;base64,">
<img src="data:image/jpeg;base64,">
<img src="data:image/jpeg;base64,">
<img src="data:image/jpeg;base64,">
<img src="data:image/jpeg;base64,">
<img src="data:image/jpeg;base64,">
<img src="data:image/jpeg;base64,">
<img src="data:image/jpeg;base64,">
<img src="data:image/jpeg;base64,">
<img src="data:image/jpeg;base64,">
<img src="data:image/jpeg;base64,">
<img src="data:image/jpeg;base64,">

</div>

</div>

</div>

`


document.body.appendChild(container)



/* 图片滑动 */

const screen=document.getElementById("iphoneScreen")
const track=document.getElementById("iphoneTrack")

const imgs=Array.from(track.children)

imgs.forEach(img=>{
track.appendChild(img.cloneNode(true))
})

let position=0
let velocity=0
let dragging=false
let startX=0


screen.addEventListener("mousedown",(e)=>{

e.preventDefault()

dragging=true
startX=e.clientX
screen.style.cursor="grabbing"

})

document.addEventListener("mouseup",()=>{

dragging=false
screen.style.cursor="grab"

})

document.addEventListener("mousemove",(e)=>{

if(!dragging) return

let dx=e.clientX-startX

/* 提高拖动灵敏度 */

position += dx

velocity = dx * 0.4

startX=e.clientX

})


function animate(){

position+=velocity
velocity*=0.92

const width=screen.offsetWidth

if(position<=-width*imgs.length){
position=0
}

if(position>0){
position=-width*imgs.length
}

track.style.transform="translateX("+position+"px)"

requestAnimationFrame(animate)

}

animate()



/* 自动轮播 */

let autoIndex=0

setInterval(()=>{

if(dragging) return

const width=screen.offsetWidth

autoIndex++

position=-width*autoIndex

if(autoIndex>=imgs.length){
autoIndex=0
position=0
}

},3000)



/* 手机拖动 */

let phoneDrag=false
let offsetX=0
let offsetY=0

container.addEventListener("mousedown",(e)=>{

if(e.target.closest(".iphone-screen")) return

phoneDrag=true

offsetX=e.clientX-container.offsetLeft
offsetY=e.clientY-container.offsetTop

})

document.addEventListener("mouseup",()=>{

if(!phoneDrag) return

phoneDrag=false

snapToEdge()

})

document.addEventListener("mousemove",(e)=>{

if(!phoneDrag) return

container.style.left=(e.clientX-offsetX)+"px"
container.style.top=(e.clientY-offsetY)+"px"

})



/* 边缘吸附 */

function snapToEdge(){

const rect=container.getBoundingClientRect()

const screenWidth=window.innerWidth
const screenHeight=window.innerHeight

const snap=80 /* 吸附距离 */

let left=rect.left
let top=rect.top

/* 左边 */

if(rect.left<snap){
left=10
}

/* 右边 */

if(screenWidth-rect.right<snap){
left=screenWidth-rect.width-10
}

/* 上边 */

if(rect.top<snap){
top=10
}

/* 下边 */

if(screenHeight-rect.bottom<snap){
top=screenHeight-rect.height-10
}

container.style.left=left+"px"
container.style.top=top+"px"

}


}


/* 首次加载 */

document.addEventListener("DOMContentLoaded",initIphone)

/* PJAX */

document.addEventListener("pjax:complete",initIphone)

})();